matches_cleaned |>
  filter(match == "Yes") |>
  select(
    name.x,
    state,
    detention_facility_code,
    name_matched = name.y,
    match,
    match_probability
  ) |>
  group_by(name.x, detention_facility_code, state) |>
  slice_max(order_by = match_probability, n = 1, with_ties = FALSE) |>
  ungroup() |>
  filter(match_probability >= 0.1) |>
  mutate(
    match_probability = round(match_probability * 100)
  ) |>
  select(-match) |>
  relocate(
    name.x,
    name_matched,
    state,
    detention_facility_code,
    match_probability
  ) |>
  clipr::write_clip()

